module debounce(
    input clk,
    input rst,
    input switch_in,

    output switch_out
);

reg [3:0] debounce_shift;
reg switch_out;

always @(posedge clk or posedge rst)
begin
  if (rst)
    debounce_shift <= 4'b0000;
  else
    debounce_shift <= {debounce_shift[2:0], switch_in};
end

always @(posedge clk or posedge rst)
begin
  if (rst)
    switch_out <= 0;
  else if (debounce_shift == 4'b1111)
    switch_out <= 1;
  else if (debounce_shift == 4'b0000)
    switch_out <= 0;
end

endmodule
